&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;converted_dataset[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;&#39;messages&#39;: [&amp;#123;&#39;role&#39;: &#39;user&#39;,
   &#39;content&#39;: [&amp;#123;&#39;type&#39;: &#39;text&#39;,
     &#39;text&#39;: &#39;Write the LaTeX representation for this image.&#39;&amp;#125;,
    &amp;#123;&#39;type&#39;: &#39;image&#39;,
     &#39;image&#39;: &amp;lt;PIL.PngImagePlugin.PngImageFile image mode=RGB size=320x50&amp;gt;&amp;#125;]&amp;#125;,
  &amp;#123;&#39;role&#39;: &#39;assistant&#39;,
   &#39;content&#39;: [&amp;#123;&#39;type&#39;: &#39;text&#39;,
     &#39;text&#39;: &#39;H ^ &amp;#123; \\prime &amp;#125; = \\beta N \\int d \\lambda \\biggl \\&amp;#123; \\frac &amp;#123; 1 &amp;#125; &amp;#123; 2 \\beta ^ &amp;#123; 2 &amp;#125; N ^ &amp;#123; 2 &amp;#125; &amp;#125; \\partial _ &amp;#123; \\lambda &amp;#125; \\zeta ^ &amp;#123; \\dagger &amp;#125; \\partial _ &amp;#123; \\lambda &amp;#125; \\zeta + V ( \\lambda ) \\zeta ^ &amp;#123; \\dagger &amp;#125; \\zeta \\biggr \\&amp;#125; \\ .&#39;&amp;#125;]&amp;#125;]&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;微调前测试&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;FastVisionModel.for_inference(model) &lt;span class=&#34;comment&#34;&gt;# Enable for inference!&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;image = dataset[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;][&lt;span class=&#34;string&#34;&gt;&amp;quot;image&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;instruction = &lt;span class=&#34;string&#34;&gt;&amp;quot;Write the LaTeX representation for this image.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;messages = [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;role&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;user&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;content&amp;quot;&lt;/span&gt;: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;type&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;image&amp;quot;&lt;/span&gt;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;type&amp;quot;&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt;: instruction&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ]&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;input_text = tokenizer.apply_chat_template(messages, add_generation_prompt = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;inputs = tokenizer(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    image,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    input_text,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    add_special_tokens = &lt;span class=&#34;literal&#34;&gt;False&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return_tensors = &lt;span class=&#34;string&#34;&gt;&amp;quot;pt&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;).to(&lt;span class=&#34;string&#34;&gt;&amp;quot;cuda&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; transformers &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; TextStreamer&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;text_streamer = TextStreamer(tokenizer, skip_prompt = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;_ = model.generate(**inputs, streamer = text_streamer, max_new_tokens = &lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                   use_cache = &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;, temperature = &lt;span class=&#34;number&#34;&gt;1.5&lt;/span&gt;, min_p = &lt;span class=&#34;number&#34;&gt;0.1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt; $$H ^ &amp;#123; \prime &amp;#125; = \beta N \int d \lambda \Bigl \&amp;#123; \frac &amp;#123; 1 &amp;#125; &amp;#123; 2 \beta ^ &amp;#123; 2 &amp;#125; N ^ &amp;#123; 2 &amp;#125; &amp;#125; \partial _ &amp;#123; \lambda &amp;#125; \zeta ^ &amp;#123; \dagger &amp;#125; \partial _ &amp;#123; \lambda &amp;#125; \zeta + V ( \lambda ) \zeta ^ &amp;#123; \dagger &amp;#125; \zeta \Bigr \&amp;#125; \; .$$&amp;lt;|im_end|&amp;gt;
&amp;lt;|endoftext|&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a name=&#34;Train&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;Train-the-model&#34;&gt;Train the model&lt;/h3&gt;
&lt;p&gt;Now let’s train our model. We do 60 steps to speed things up, but you can set &lt;code&gt;num_train_epochs=1&lt;/code&gt; for a full run, and turn off &lt;code&gt;max_steps=None&lt;/code&gt;. We also support &lt;code&gt;DPOTrainer&lt;/code&gt; and &lt;code&gt;GRPOTrainer&lt;/code&gt; for reinforcement learning!&lt;/p&gt;
&lt;p&gt;We use our new &lt;code&gt;UnslothVisionDataCollator&lt;/code&gt; which will help in our vision finetuning setup.&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; unsloth.trainer &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; UnslothVisionDataCollator&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; trl &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; SFTTrainer, SFTConfig&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FastVisionModel.for_training(model) &lt;span class=&#34;comment&#34;&gt;# Enable for training!&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;trainer = SFTTrainer(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    model = model,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tokenizer = tokenizer,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    data_collator = UnslothVisionDataCollator(model, tokenizer), &lt;span class=&#34;comment&#34;&gt;# Must use!&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    train_dataset = converted_dataset,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    args = SFTConfig(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        per_device_train_batch_size = &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        gradient_accumulation_steps = &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        warmup_steps = &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        max_steps = &lt;span class=&#34;number&#34;&gt;30&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;# num_train_epochs = 1, # Set this instead of max_steps for full training runs&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        learning_rate = &lt;span class=&#34;number&#34;&gt;2e-4&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logging_steps = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        optim = &lt;span class=&#34;string&#34;&gt;&amp;quot;adamw_8bit&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        weight_decay = &lt;span class=&#34;number&#34;&gt;0.001&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        lr_scheduler_type = &lt;span class=&#34;string&#34;&gt;&amp;quot;linear&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        seed = &lt;span class=&#34;number&#34;&gt;3407&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        output_dir = &lt;span class=&#34;string&#34;&gt;&amp;quot;outputs&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        report_to = &lt;span class=&#34;string&#34;&gt;&amp;quot;none&amp;quot;&lt;/span&gt;,     &lt;span class=&#34;comment&#34;&gt;# For Weights and Biases&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;# You MUST put the below items for vision finetuning:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        remove_unused_columns = &lt;span class=&#34;literal&#34;&gt;False&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dataset_text_field = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dataset_kwargs = &amp;#123;&lt;span class=&#34;string&#34;&gt;&amp;quot;skip_prepare_dataset&amp;quot;&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        max_length = &lt;span class=&#34;number&#34;&gt;2048&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @title Show current memory stats&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gpu_stats = torch.cuda.get_device_properties(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;start_gpu_memory = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(torch.cuda.max_memory_reserved() / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;max_memory = &lt;span class=&#34;built_in&#34;&gt;round&lt;/span&gt;(gpu_stats.total_memory / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; / &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;GPU = &lt;span class=&#34;subst&#34;&gt;&amp;#123;gpu_stats.name&amp;#125;&lt;/span&gt;. Max memory = &lt;span class=&#34;subst&#34;&gt;&amp;#123;max_memory&amp;#125;&lt;/span&gt; GB.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;f&amp;quot;&lt;span class=&#34;subst&#34;&gt;&amp;#123;start_gpu_memory&amp;#125;&lt;/span&gt; GB of memory reserved.&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;Unsloth: Model does not have a default image size - using 512
Unsloth: Switching to float32 training since model cannot work with float16
GPU = Tesla T4. Max memory = 14.563 GB.
9.68 GB of memory reserved.
&lt;/code&gt;&lt;/pre&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;trainer_stats = trainer.train()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
